sql:
SELECT films.title, budgets.total_budget
FROM films
INNER JOIN budgets ON films.film_id = budgets.film_id;

SELECT f.title
FROM films f
WHERE f.budget > (SELECT AVG(budget) FROM films);

SELECT item_name, amount, status
FROM budget_items
WHERE amount = (SELECT MAX(amount) FROM budget_items);

SELECT f.title, b.spent_budget
FROM films f
JOIN budgets b ON f.film_id = b.film_id;

SELECT DISTINCT films.title, film_genres.genre_id
FROM films
JOIN film_genres ON films.film_id = film_genres.film_id;

SELECT f.title, b.spent_budget AS Total_Budget_Spent
FROM films f
INNER JOIN budgets b ON f.film_id = b.film_id;
